#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t U,V,A,S; scanf("%lld %lld %lld %lld", &U,&V,&A,&S);
        int64_t left = U*U;
        int64_t right = V*V + 2LL*A*S;
        if(left <= right) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

